changeSet.createView:
SELECT /* ── Écriture comptable ───────────────────────────────────── */ cpt.IDCOMPTABILITE, cpt.DATEOPERATION, cpt.NUMPIECE AS num_piece, cpt.LIBELLE, cpt.planComptable AS num_compte, cpt.Compte1 AS compte_contrepartie, cpt.CompteAuxi AS compte_auxiliaire, cpt.CODE_SENS AS sens, cpt.DEBIT, cpt.CREDIT, cpt.REFERENCE,
/* ── Agence ──────────────────────────────────────────────── */ cpt.agence AS code_agence, ag.NOMAGENCE AS nom_agence, cpt.utilisateur AS agent_saisie,
/* ── Type d'opération déduit ─────────────────────────────── */ CASE WHEN r.IDREGLEMENT IS NOT NULL THEN 'REMBOURSEMENT' ELSE 'OPERATION' END AS type_operation,
/* ── Montant net selon le sens ───────────────────────────── */ CASE WHEN cpt.CODE_SENS = 'D' THEN cpt.DEBIT ELSE cpt.CREDIT END AS montant_net,
/* ── Détail remboursement (NULL si non lié à un Reglement) ─ */ r.IDREGLEMENT, r.DATE_REGLEMENT, r.MONTANT_TOTAL AS montant_reglement, r.MONTANT_CAPITAL, r.MONTANT_INTERET, r.MONTANT_PENALITE, r.MONTANT_ASSURANCE, r.MONTANT_COMMISSION, r.MONTANT_TAXE, r.MODE_PAIEMENT, r.STATUT AS statut_reglement,
/* ── Crédit lié (via Reglement) ──────────────────────────── */ r.idcredit AS idcredit_reglement, c.NUMCREDIT AS numcredit_reglement
FROM comptabilite cpt
LEFT JOIN AGENCE ag ON ag.CODE_AGENCE = cpt.agence
LEFT JOIN Reglement r ON r.idcomptabilite = cpt.IDCOMPTABILITE
LEFT JOIN Credits c ON c.IDCREDIT = r.idcredit
